/**
 * CortexBuild Ultimate — WebSocket Server
 * Real-time notifications, live dashboard updates, collaborative features
 */

const WebSocket = require('ws');
const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'cortexbuild-secret-key';

// Message types
const MESSAGE_TYPES = {
  NOTIFICATION: 'notification',
  DASHBOARD_UPDATE: 'dashboard_update',
  ALERT: 'alert',
  COLLABORATION: 'collaboration',
  SYSTEM: 'system',
};

// Connection store
const clients = new Map(); // Map<userId, Set<WebSocket>>
const rooms = new Map();   // Map<roomId, Set<userId>>

/**
 * Initialize WebSocket server
 * @param {http.Server} server - HTTP server to attach to
 */
function initWebSocket(server) {
  const wss = new WebSocket.Server({ server, path: '/ws' });

  wss.on('connection', (ws, req) => {
    console.log('[WS] New connection');

    // Authenticate connection
    const token = extractToken(req.url);
    if (!token || !verifyToken(token)) {
      ws.close(4001, 'Unauthorized');
      return;
    }

    const userId = decodeToken(token).id;
    const userRooms = new Set();

    // Register client
    if (!clients.has(userId)) {
      clients.set(userId, new Set());
    }
    clients.get(userId).add(ws);

    // Auto-join user's personal room
    userRooms.add(`user:${userId}`);
    joinRoom(userId, `user:${userId}`);

    // Handle messages
    ws.on('message', (data) => {
      try {
        const message = JSON.parse(data.toString());
        handleMessage(ws, userId, message);
      } catch (err) {
        console.error('[WS] Message parse error:', err.message);
        sendError(ws, 'Invalid message format');
      }
    });

    // Handle connection close
    ws.on('close', () => {
      console.log('[WS] Connection closed');
      clients.get(userId)?.delete(ws);
      if (clients.get(userId)?.size === 0) {
        clients.delete(userId);
      }
      // Leave all rooms
      userRooms.forEach(room => leaveRoom(userId, room));
    });

    // Send welcome message
    sendToClient(ws, {
      type: MESSAGE_TYPES.SYSTEM,
      event: 'connected',
      payload: {
        message: 'Connected to CortexBuild real-time service',
        timestamp: new Date().toISOString(),
      },
    });
  });

  console.log('[WS] WebSocket server initialized on /ws');
  return wss;
}

/**
 * Extract JWT token from WebSocket URL query string
 */
function extractToken(url) {
  const urlObj = new URL(url, 'ws://localhost');
  return urlObj.searchParams.get('token');
}

/**
 * Verify JWT token
 */
function verifyToken(token) {
  try {
    jwt.verify(token, JWT_SECRET);
    return true;
  } catch (err) {
    console.error('[WS] Token verification failed');
    return false;
  }
}

/**
 * Decode JWT token
 */
function decodeToken(token) {
  return jwt.decode(token);
}

/**
 * Send message to specific client
 */
function sendToClient(ws, message) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(message));
  }
}

/**
 * Send message to all clients of a user
 */
function sendToUser(userId, message) {
  const userClients = clients.get(userId);
  if (userClients) {
    userClients.forEach(ws => sendToClient(ws, message));
  }
}

/**
 * Send message to room
 */
function sendToRoom(roomId, message, excludeUserId = null) {
  const room = rooms.get(roomId);
  if (room) {
    room.forEach(userId => {
      if (userId !== excludeUserId) {
        sendToUser(userId, message);
      }
    });
  }
}

/**
 * Broadcast to all connected clients
 */
function broadcast(message) {
  clients.forEach((userClients, userId) => {
    userClients.forEach(ws => sendToClient(ws, message));
  });
}

/**
 * Join room
 */
function joinRoom(userId, roomId) {
  if (!rooms.has(roomId)) {
    rooms.set(roomId, new Set());
  }
  rooms.get(roomId).add(userId);
}

/**
 * Leave room
 */
function leaveRoom(userId, roomId) {
  const room = rooms.get(roomId);
  if (room) {
    room.delete(userId);
    if (room.size === 0) {
      rooms.delete(roomId);
    }
  }
}

/**
 * Handle incoming message
 */
function handleMessage(ws, userId, message) {
  const { type, event, payload, room } = message;

  switch (event) {
    case 'join_room':
      joinRoom(userId, payload.room);
      sendToClient(ws, {
        type: MESSAGE_TYPES.SYSTEM,
        event: 'room_joined',
        payload: { room: payload.room },
      });
      break;

    case 'leave_room':
      leaveRoom(userId, payload.room);
      sendToClient(ws, {
        type: MESSAGE_TYPES.SYSTEM,
        event: 'room_left',
        payload: { room: payload.room },
      });
      break;

    case 'send_notification':
      // Send notification to specific user or room
      if (payload.userId) {
        sendToUser(payload.userId, {
          type: MESSAGE_TYPES.NOTIFICATION,
          event: 'notification',
          payload: {
            from: userId,
            ...payload.data,
            timestamp: new Date().toISOString(),
          },
        });
      } else if (payload.room) {
        sendToRoom(payload.room, {
          type: MESSAGE_TYPES.NOTIFICATION,
          event: 'notification',
          payload: {
            from: userId,
            ...payload.data,
            timestamp: new Date().toISOString(),
          },
        });
      }
      break;

    case 'broadcast':
      broadcast({
        type: MESSAGE_TYPES.SYSTEM,
        event: 'broadcast',
        payload: {
          from: userId,
          ...payload,
          timestamp: new Date().toISOString(),
        },
      });
      break;

    default:
      sendError(ws, `Unknown event: ${event}`);
  }
}

/**
 * Send error message
 */
function sendError(ws, errorMessage) {
  sendToClient(ws, {
    type: MESSAGE_TYPES.SYSTEM,
    event: 'error',
    payload: { message: errorMessage },
  });
}

/**
 * Create notification helper
 */
function createNotification(userId, title, description, severity = 'info', data = {}) {
  sendToUser(userId, {
    type: MESSAGE_TYPES.NOTIFICATION,
    event: 'notification',
    payload: {
      title,
      description,
      severity,
      ...data,
      timestamp: new Date().toISOString(),
    },
  });
}

/**
 * Create alert helper (high priority notification)
 */
function createAlert(userId, title, description, data = {}) {
  sendToUser(userId, {
    type: MESSAGE_TYPES.ALERT,
    event: 'alert',
    payload: {
      title,
      description,
      priority: 'high',
      ...data,
      timestamp: new Date().toISOString(),
    },
  });
}

/**
 * Dashboard update helper
 */
function sendDashboardUpdate(userId, updates) {
  sendToUser(userId, {
    type: MESSAGE_TYPES.DASHBOARD_UPDATE,
    event: 'dashboard_update',
    payload: {
      updates,
      timestamp: new Date().toISOString(),
    },
  });
}

/**
 * Project room helpers
 */
function createProjectRoom(projectId, userId) {
  joinRoom(userId, `project:${projectId}`);
}

function notifyProjectTeam(projectId, title, description, excludeUserId = null) {
  sendToRoom(`project:${projectId}`, {
    type: MESSAGE_TYPES.COLLABORATION,
    event: 'project_notification',
    payload: {
      projectId,
      title,
      description,
      timestamp: new Date().toISOString(),
    },
  }, excludeUserId);
}

// Export for use in routes
module.exports = {
  initWebSocket,
  createNotification,
  createAlert,
  sendDashboardUpdate,
  createProjectRoom,
  notifyProjectTeam,
  broadcast,
  MESSAGE_TYPES,
};

const express = require('express');
const bcrypt  = require('bcrypt');
const jwt     = require('jsonwebtoken');
const pool    = require('../db');
const authMiddleware = require('../middleware/auth');

const router = express.Router();
const SECRET = process.env.JWT_SECRET || 'cortexbuild_secret';

const VALID_ROLES = ['super_admin','company_owner','admin','project_manager','field_worker','client'];

// POST /api/auth/register — public self-registration (creates company_owner account)
router.post('/register', async (req, res) => {
  const { name, email, password, company, phone } = req.body;

  if (!name || !email || !password || !company) {
    return res.status(400).json({ message: 'Name, email, password and company are required' });
  }
  if (password.length < 8) {
    return res.status(400).json({ message: 'Password must be at least 8 characters' });
  }
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRe.test(email)) {
    return res.status(400).json({ message: 'Invalid email address' });
  }

  try {
    // Check for duplicate email
    const existing = await pool.query('SELECT id FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    if (existing.rows.length) {
      return res.status(409).json({ message: 'An account with that email already exists' });
    }

    const hash = await bcrypt.hash(password, 10);
    const { rows } = await pool.query(
      `INSERT INTO users (name, email, password_hash, role, company, phone)
       VALUES ($1, $2, $3, 'company_owner', $4, $5)
       RETURNING id, name, email, role, company, phone, created_at`,
      [name.trim(), email.toLowerCase().trim(), hash, company.trim(), phone || null]
    );
    const newUser = rows[0];

    const token = jwt.sign(
      { id: newUser.id, email: newUser.email, role: newUser.role, name: newUser.name, company: newUser.company },
      SECRET,
      { expiresIn: '7d' }
    );

    res.status(201).json({ token, user: newUser });
  } catch (err) {
    console.error('[auth/register]', err);
    res.status(500).json({ message: 'Server error during registration' });
  }
});

// POST /api/auth/login
router.post('/login', async (req, res) => {
  const { email, password } = req.body;
  if (!email || !password) return res.status(400).json({ message: 'Email and password required' });

  try {
    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    const user = rows[0];
    if (!user) return res.status(401).json({ message: 'Invalid email or password' });

    const valid = await bcrypt.compare(password, user.password_hash);
    if (!valid) return res.status(401).json({ message: 'Invalid email or password' });

    const token = jwt.sign(
      { id: user.id, email: user.email, role: user.role, name: user.name, company: user.company },
      SECRET,
      { expiresIn: '7d' }
    );

    const { password_hash, ...safeUser } = user;
    res.json({ token, user: safeUser });
  } catch (err) {
    console.error('[auth/login]', err);
    res.status(500).json({ message: 'Server error' });
  }
});

// GET /api/auth/me
router.get('/me', authMiddleware, async (req, res) => {
  try {
    const { rows } = await pool.query(
      'SELECT id,name,email,role,company,phone,avatar,created_at FROM users WHERE id = $1',
      [req.user.id]
    );
    if (!rows[0]) return res.status(404).json({ message: 'User not found' });
    res.json(rows[0]);
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// PUT /api/auth/profile
router.put('/profile', authMiddleware, async (req, res) => {
  const { name, phone } = req.body;
  try {
    const { rows } = await pool.query(
      'UPDATE users SET name=$1, phone=$2 WHERE id=$3 RETURNING id,name,email,role,company,phone,avatar',
      [name, phone, req.user.id]
    );
    res.json(rows[0]);
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// PUT /api/auth/password
router.put('/password', authMiddleware, async (req, res) => {
  const { currentPassword, newPassword } = req.body;
  if (!currentPassword || !newPassword) return res.status(400).json({ message: 'Both passwords required' });
  if (newPassword.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });

  try {
    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [req.user.id]);
    const user = rows[0];
    const valid = await bcrypt.compare(currentPassword, user.password_hash);
    if (!valid) return res.status(400).json({ message: 'Current password is incorrect' });

    const hash = await bcrypt.hash(newPassword, 10);
    await pool.query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.user.id]);
    res.json({ message: 'Password updated successfully' });
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// GET /api/auth/users — list all users (admin+ only)
router.get('/users', authMiddleware, async (req, res) => {
  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
    return res.status(403).json({ message: 'Insufficient permissions' });
  }
  try {
    const { rows } = await pool.query(
      'SELECT id,name,email,role,company,phone,avatar,created_at FROM users ORDER BY created_at DESC'
    );
    res.json(rows);
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// POST /api/auth/users — create user (admin+ only)
router.post('/users', authMiddleware, async (req, res) => {
  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
    return res.status(403).json({ message: 'Insufficient permissions' });
  }

  const { name, email, password, role = 'project_manager', company, phone } = req.body;
  if (!name || !email || !password) return res.status(400).json({ message: 'Name, email, and password are required' });
  if (password.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
  if (!VALID_ROLES.includes(role)) return res.status(400).json({ message: `Invalid role. Must be one of: ${VALID_ROLES.join(', ')}` });

  try {
    const hash = await bcrypt.hash(password, 10);
    const { rows } = await pool.query(
      'INSERT INTO users (name,email,password_hash,role,company,phone) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id,name,email,role,company,phone,created_at',
      [name, email.toLowerCase().trim(), hash, role, company || 'CortexBuild Ltd', phone || null]
    );
    res.status(201).json(rows[0]);
  } catch (err) {
    if (err.code === '23505') return res.status(409).json({ message: 'Email already in use' });
    console.error('[auth/users POST]', err);
    res.status(500).json({ message: 'Server error' });
  }
});

// DELETE /api/auth/users/:id — delete user (super_admin / company_owner only)
router.delete('/users/:id', authMiddleware, async (req, res) => {
  if (!['super_admin','company_owner'].includes(req.user.role)) {
    return res.status(403).json({ message: 'Insufficient permissions' });
  }
  if (req.params.id === req.user.id) return res.status(400).json({ message: 'Cannot delete your own account' });

  try {
    const { rowCount } = await pool.query('DELETE FROM users WHERE id = $1', [req.params.id]);
    if (!rowCount) return res.status(404).json({ message: 'User not found' });
    res.json({ message: 'User deleted' });
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// PUT /api/auth/avatar
router.put('/avatar', authMiddleware, async (req, res) => {
  const { avatar } = req.body;
  if (!avatar) return res.status(400).json({ message: 'Avatar URL required' });
  try {
    const { rows } = await pool.query(
      'UPDATE users SET avatar=$1 WHERE id=$2 RETURNING id,name,email,role,company,phone,avatar',
      [avatar, req.user.id]
    );
    res.json(rows[0]);
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// GET /api/auth/settings — get all user settings
router.get('/settings', authMiddleware, async (req, res) => {
  try {
    const { rows } = await pool.query(
      'SELECT key, value FROM app_settings WHERE user_id=$1',
      [req.user.id]
    );
    const settings = Object.fromEntries(rows.map(r => [r.key, r.value]));
    res.json(settings);
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

// PUT /api/auth/settings — upsert a setting key
router.put('/settings', authMiddleware, async (req, res) => {
  const { key, value } = req.body;
  if (!key) return res.status(400).json({ message: 'key required' });
  try {
    await pool.query(
      `INSERT INTO app_settings (user_id, key, value)
       VALUES ($1, $2, $3::jsonb)
       ON CONFLICT (user_id, key) DO UPDATE SET value=$3::jsonb, updated_at=now()`,
      [req.user.id, key, JSON.stringify(value)]
    );
    res.json({ key, value });
  } catch (err) {
    res.status(500).json({ message: 'Server error' });
  }
});

module.exports = router;

