    all: [], incidents: ['incident','first_aid','riddor'], near_misses: ['near-miss','near_miss'],
    hazards: ['hazard','dangerous_occurrence','environmental'], mewp: ['mewp-check','mewp_check'],
    toolbox: ['toolbox-talk','toolbox_talk'], riddor: ['riddor'],
