  const formNet = formGross - formDeduction;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-white">CIS Returns</h1>
          <p className="text-sm text-gray-400 mt-1">Construction Industry Scheme — monthly deduction records</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors">
          <Plus size={16}/><span>New Return</span>
        </button>
      </div>

      {overdueCount > 0 && (
        <div className="flex items-center gap-3 bg-red-900/30 border border-red-700 rounded-xl px-4 py-3">
          <AlertCircle size={18} className="text-red-400 flex-shrink-0"/>
          <p className="text-sm text-red-300"><span className="font-semibold">{overdueCount} overdue return{overdueCount>1?'s':''}</span> — submit to HMRC to avoid penalties.</p>
        </div>
      )}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'Total Gross Payments', value:`£${totalGross.toLocaleString()}`, icon:PoundSterling, colour:'text-blue-400' },
          { label:'Total CIS Deducted', value:`£${Math.round(totalDeduction).toLocaleString()}`, icon:Calculator, colour:'text-orange-400' },
          { label:'Submitted', value:submittedCount, icon:CheckCircle, colour:'text-green-400' },
          { label:'Overdue', value:overdueCount, icon:Clock, colour:overdueCount>0?'text-red-400':'text-gray-400' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 border border-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-gray-400">{kpi.label}</p>
              <kpi.icon size={18} className={kpi.colour}/>
            </div>
            <p className={`text-2xl font-bold ${kpi.colour}`}>{kpi.value}</p>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-700">
        {([
          { key:'all', label:'All Returns', filter:'All', count:returns.length, cls:'' },
          { key:'draft', label:'Draft', filter:'Draft', count:returns.filter(r=>r.status==='Draft').length, cls:'' },
          { key:'submitted', label:'Submitted', filter:'Submitted', count:submittedCount, cls:'' },
          { key:'overdue', label:'Overdue', filter:'Overdue', count:overdueCount, cls:'bg-red-900/40 text-red-400' },
        ]).map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-orange-500 text-orange-400':'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.cls||'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 border border-gray-800 rounded-xl p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search subcontractor…"
            className="w-full pl-9 pr-4 py-2 text-sm bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-orange-500"/>
        </div>
        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)}
          className="text-sm bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500">
          {['All',...STATUS_OPTIONS].map(s=><option key={s}>{s}</option>)}
        </select>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"/></div>
      ) : (
        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-gray-800/60 border-b border-gray-700">
              <tr>{['Subcontractor','UTR','Tax Period','Gross','Materials','CIS Rate','Deduction','Net Pay','Status',''].map(h=>(
                <th key={h} className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide whitespace-nowrap">{h}</th>
              ))}</tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {filtered.map(r=>{
                const deduction = calcDeduction(r);
                const net = calcNet(r);
                return (
                  <tr key={String(r.id)} className="hover:bg-gray-800/40 transition-colors">
                    <td className="px-4 py-3 font-medium text-white">{String(r.contractor??'—')}</td>
                    <td className="px-4 py-3 text-gray-400 font-mono text-xs">{String(r.utr??'—')}</td>
                    <td className="px-4 py-3 text-gray-300">{String(r.period??'—')}</td>
                    <td className="px-4 py-3 text-white font-medium">£{Number(r.gross_payment??0).toLocaleString()}</td>
                    <td className="px-4 py-3 text-gray-400">£{Number(r.materials_cost??0).toLocaleString()}</td>
                    <td className="px-4 py-3">
                      <span className="text-xs bg-blue-900/50 text-blue-300 px-2 py-0.5 rounded-full font-medium">{Number(r.cis_rate??20)}%</span>
                    </td>
                    <td className="px-4 py-3 font-semibold text-red-400">-£{Math.round(deduction).toLocaleString()}</td>
                    <td className="px-4 py-3 font-semibold text-green-400">£{Math.round(net).toLocaleString()}</td>
                    <td className="px-4 py-3">
                      <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(r.status??'')] ?? 'bg-gray-700 text-gray-300'}`}>
                        {String(r.status??'')}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        {r.status === 'Draft' && (
                          <button onClick={()=>markSubmitted(r)} className="p-1.5 text-green-400 hover:bg-green-900/40 rounded" title="Submit">
                            <CheckCircle size={14}/>
                          </button>
                        )}
                        <button onClick={()=>openEdit(r)} className="p-1.5 text-gray-400 hover:text-blue-400 hover:bg-blue-900/30 rounded"><Edit2 size={14}/></button>
                        <button onClick={()=>handleDelete(String(r.id))} className="p-1.5 text-gray-400 hover:text-red-400 hover:bg-red-900/30 rounded"><Trash2 size={14}/></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length === 0 && (
            <div className="text-center py-16 text-gray-500">
              <Receipt size={40} className="mx-auto mb-3 opacity-30"/><p>No CIS returns found</p>
            </div>
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 border border-gray-700 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-bold text-white">{editing?'Edit CIS Return':'New CIS Return'}</h2>
              <button onClick={()=>setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400 hover:text-white"><X size={18}/></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              {(formGross > 0) && (
                <div className="grid grid-cols-3 gap-3 bg-gray-800 rounded-xl p-4 text-sm">
                  <div className="text-center"><p className="text-xs text-blue-400 mb-1">Gross Payment</p><p className="font-bold text-white">£{formGross.toLocaleString()}</p></div>
                  <div className="text-center"><p className="text-xs text-red-400 mb-1">CIS Deduction</p><p className="font-bold text-red-300">-£{Math.round(formDeduction).toLocaleString()}</p></div>
                  <div className="text-center"><p className="text-xs text-green-400 mb-1">Net to Pay</p><p className="font-bold text-green-300">£{Math.round(formNet).toLocaleString()}</p></div>
                </div>
              )}
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Subcontractor Name *</label>
                  <input required value={form.contractor} onChange={e=>setForm(f=>({...f,contractor:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">UTR Number</label>
                  <input value={form.utr} onChange={e=>setForm(f=>({...f,utr:e.target.value}))} placeholder="10-digit UTR"
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Tax Period</label>
                  <select value={form.period} onChange={e=>setForm(f=>({...f,period:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    <option value="">Select…</option>{TAX_PERIOD_OPTIONS.map(p=><option key={p}>{p}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Gross Payment (£)</label>
                  <input type="number" value={form.gross_payment} onChange={e=>setForm(f=>({...f,gross_payment:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Materials (£)</label>
                  <input type="number" value={form.materials} onChange={e=>setForm(f=>({...f,materials:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">CIS Deduction Rate</label>
                  <select value={form.cis_rate} onChange={e=>setForm(f=>({...f,cis_rate:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    {CIS_RATES.map(r=><option key={r.value} value={r.value}>{r.label}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Status</label>
                  <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    {STATUS_OPTIONS.map(s=><option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Payment Date</label>
                  <input type="date" value={form.payment_date} onChange={e=>setForm(f=>({...f,payment_date:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Notes</label>
                  <textarea rows={2} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500 resize-none"/>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={()=>setShowModal(false)}
                  className="flex-1 px-4 py-2 bg-gray-800 hover:bg-gray-700 rounded-lg text-sm text-white font-medium transition-colors">Cancel</button>
                <button type="submit" disabled={createMutation.isPending||updateMutation.isPending}
                  className="flex-1 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors disabled:opacity-50">
                  {editing?'Update Return':'Create Return'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { ClipboardList, Plus, Search, CloudRain, Sun, Cloud, Wind, Users, Edit2, Trash2, X, ChevronDown, ChevronUp, Calendar, AlertTriangle } from 'lucide-react';
import { useDailyReports } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const WEATHER_OPTIONS = ['Sunny','Partly Cloudy','Overcast','Light Rain','Heavy Rain','Fog','High Wind','Snow','Frost'];
const STATUS_OPTIONS = ['Draft','Submitted','Approved'];

const statusColour: Record<string,string> = {
  'Draft':'bg-gray-800 text-gray-600','Submitted':'bg-blue-500/20 text-blue-300','Approved':'bg-green-500/20 text-green-300',
};

const weatherIcon = (w: string) => {
  if (w.includes('Rain')) return <CloudRain size={14} className="text-blue-500"/>;
  if (w.includes('Sun') || w.includes('Sunny')) return <Sun size={14} className="text-yellow-500"/>;
  if (w.includes('Wind')) return <Wind size={14} className="text-gray-500"/>;
  return <Cloud size={14} className="text-gray-400"/>;
};

const emptyForm = { report_date:'',project_id:'',weather:'Sunny',temp_high:'',temp_low:'',workers_on_site:'',work_carried_out:'',delays:'',safety_observations:'',visitors:'',status:'Draft',submitted_by:'' };

export function DailyReports() {
  const { useList, useCreate, useUpdate, useDelete } = useDailyReports;
  const { data: raw = [], isLoading } = useList();
  const reports = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState<'today'|'week'|'all'|'drafts'>('today');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [expanded, setExpanded] = useState<string | null>(null);

  const today = new Date().toISOString().slice(0,10);

  const filtered = reports.filter(r => {
    const date = String(r.report_date??'');
    const work = String(r.work_carried_out??'').toLowerCase();
    const matchSearch = date.includes(search) || work.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'All' || r.status === statusFilter;
    if (!matchSearch || !matchStatus) return false;
    if (subTab === 'today') return date === today;
    if (subTab === 'week') {
      const diff = (Date.now() - new Date(date).getTime()) / 86400000;
      return diff >= 0 && diff <= 7;
    }
    if (subTab === 'drafts') return r.status === 'Draft';
    return true; // 'all'
  });

  const thisWeekCount = reports.filter(r => {
    const d = new Date(String(r.report_date??''));
    const diff = (Date.now() - d.getTime()) / 86400000;
    return diff >= 0 && diff <= 7;
  }).length;
  const draftCount = reports.filter(r=>r.status==='Draft').length;
  const totalWorkerDays = reports.reduce((s,r)=>s+Number(r.workers_on_site??0),0);
  const delayCount = reports.filter(r=>String(r.delays??'').trim().length>0).length;

  function openCreate() {
    setEditing(null);
    setForm({ ...emptyForm, report_date:today });
    setShowModal(true);
  }
  function openEdit(r: AnyRow) {
    setEditing(r);
    setForm({ report_date:String(r.report_date??''),project_id:String(r.project_id??''),weather:String(r.weather??'Sunny'),temp_high:String(r.temp_high??''),temp_low:String(r.temp_low??''),workers_on_site:String(r.workers_on_site??''),work_carried_out:String(r.work_carried_out??''),delays:String(r.delays??''),safety_observations:String(r.safety_observations??''),visitors:String(r.visitors??''),status:String(r.status??'Draft'),submitted_by:String(r.submitted_by??'') });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, workers_on_site:Number(form.workers_on_site)||0, temp_high:Number(form.temp_high)||null, temp_low:Number(form.temp_low)||null };
    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Report updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Report submitted'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this daily report?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Report deleted');
  }

  async function submitReport(r: AnyRow) {
    await updateMutation.mutateAsync({ id:String(r.id), data:{ status:'Submitted' } });
    toast.success('Report submitted for approval');
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Daily Site Reports</h1>
          <p className="text-sm text-gray-500 mt-1">Daily progress, weather & site records</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16}/><span>New Report</span>
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'This Week', value:thisWeekCount, icon:Calendar, colour:'text-blue-400', bg:'bg-blue-500/20' },
          { label:'Drafts', value:draftCount, icon:ClipboardList, colour:'text-yellow-400', bg:'bg-yellow-500/20' },
          { label:'Worker Days', value:totalWorkerDays, icon:Users, colour:'text-green-400', bg:'bg-green-500/20' },
          { label:'Delays Reported', value:delayCount, icon:AlertTriangle, colour:delayCount>0?'text-orange-400':'text-gray-600', bg:delayCount>0?'bg-orange-500/20':'bg-gray-900' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 rounded-xl border border-gray-700 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour}/></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-white">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="border-b border-gray-700 flex gap-1">
        {([
          { key:'today' as const,  label:'Today',     count:reports.filter(r=>String(r.report_date??'')===today).length, cls:'' },
          { key:'week'  as const,  label:'This Week',  count:thisWeekCount, cls:'' },
          { key:'drafts' as const, label:'Drafts',     count:draftCount, cls:'bg-yellow-500/20 text-yellow-300' },
          { key:'all'   as const,  label:'All Reports', count:reports.length, cls:'' },
        ]).map(t=>(
          <button key={t.key} onClick={()=>setSubTab(t.key)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-orange-500 text-orange-400':'border-transparent text-gray-500 hover:text-gray-300'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.cls||'bg-gray-800 text-gray-300'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 rounded-xl border border-gray-700 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search date or work description…" className="w-full pl-9 pr-4 py-2 text-sm bg-gray-800 border border-gray-700 text-white placeholder-gray-500 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"/>
        </div>
        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)} className="text-sm bg-gray-800 border border-gray-700 text-white rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-orange-500">
          {['All',...STATUS_OPTIONS].map(s=><option key={s}>{s}</option>)}
        </select>
        <span className="text-sm text-gray-500 ml-auto">{filtered.length} reports</span>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-600"/></div>
      ) : (
        <div className="bg-gray-900 rounded-xl border border-gray-700 divide-y divide-gray-700">
          {filtered.length === 0 && <div className="text-center py-16 text-gray-400"><ClipboardList size={40} className="mx-auto mb-3 opacity-30"/><p>No daily reports found</p></div>}
          {filtered.map(r => {
            const id = String(r.id??'');
            const isExp = expanded === id;
            return (
              <div key={id}>
                <div className="flex items-center gap-4 p-4 hover:bg-gray-800 cursor-pointer" onClick={()=>setExpanded(isExp?null:id)}>
                  <div className="w-20 flex-shrink-0 text-center">
                    <p className="text-sm font-bold text-gray-100">{String(r.report_date??'—')}</p>
                  </div>
                  <div className="flex items-center gap-1.5 flex-shrink-0">
                    {weatherIcon(String(r.weather??''))}
                    <span className="text-xs text-gray-500">{String(r.weather??'—')}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm text-gray-300 truncate">{String(r.work_carried_out??'No description')}</p>
                    <div className="flex items-center gap-3 mt-0.5">
                      {!!r.workers_on_site && <span className="text-xs text-gray-500 flex items-center gap-1"><Users size={11}/>{String(r.workers_on_site)} workers</span>}
                      {!!r.delays && <span className="text-xs text-orange-400 flex items-center gap-1"><AlertTriangle size={11}/>Delays noted</span>}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(r.status??'')] ?? 'bg-gray-800 text-gray-300'}`}>{String(r.status??'')}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    {r.status==='Draft' && <button onClick={e=>{e.stopPropagation();submitReport(r);}} className="p-1.5 text-blue-400 hover:bg-blue-500/20 rounded text-xs" title="Submit"><ClipboardList size={14}/></button>}
                    <button onClick={e=>{e.stopPropagation();openEdit(r);}} className="p-1.5 text-gray-400 hover:text-blue-400 hover:bg-blue-500/20 rounded"><Edit2 size={14}/></button>
                    <button onClick={e=>{e.stopPropagation();handleDelete(id);}} className="p-1.5 text-gray-400 hover:text-red-400 hover:bg-red-500/20 rounded"><Trash2 size={14}/></button>
                    {isExp?<ChevronUp size={16} className="text-gray-400"/>:<ChevronDown size={16} className="text-gray-400"/>}
                  </div>
                </div>
                {isExp && (
