server {
    listen 80;
    server_name cortexbuildpro.com www.cortexbuildpro.com;

    # Redirect all HTTP to HTTPS
    return 301 https://cortexbuildpro.com$request_uri;
}

server {
    listen 443 ssl http2;
    server_name cortexbuildpro.com www.cortexbuildpro.com;

    ssl_certificate     /etc/letsencrypt/live/cortexbuildpro.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/cortexbuildpro.com/privkey.pem;
    include             /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam         /etc/letsencrypt/ssl-dhparams.pem;

    # Redirect www to non-www
    if ($host = www.cortexbuildpro.com) {
        return 301 https://cortexbuildpro.com$request_uri;
    }

    root /var/www/cortexbuild-ultimate/dist;
    index index.html;

    location /api/ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_cache_bypass $http_upgrade;
        client_max_body_size 50M;
    }

    location /ws {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_read_timeout 86400;
    }

    location /uploads/ {
        proxy_pass http://127.0.0.1:3001;
    }

    location / {
        try_files $uri $uri/ /index.html;
    }

    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }
}

